import { ContentRecord } from "./db";

/** Shared type used across the frontend UI */
export interface ContentItem {
    id: bigint;
    title: string;
    description: string;
    genre: string;
    priceLamports: bigint;
    mediaCid: string;
    thumbnail: string;
    streamer: string;
    duration: string;
    year: number;
    rating: string;
}

/** Convert an API ContentRecord to the UI ContentItem shape */
export function toContentItem(r: ContentRecord): ContentItem {
    return {
        id: BigInt(r.id),
        title: r.title,
        description: r.description,
        genre: r.genre,
        priceLamports: BigInt(Math.round(r.price_sol * 1_000_000_000)),
        mediaCid: r.video_url,
        thumbnail: r.thumbnail,
        streamer: r.wallet,
        duration: r.duration,
        year: r.year,
        rating: `★ ${r.rating}`,
    };
}

export function lamportsToSol(lamports: bigint): string {
    return (Number(lamports) / 1_000_000_000).toFixed(3) + " SOL";
}

/** Fetch all content items from the API (server or client safe) */
export async function fetchContent(params?: Record<string, string>): Promise<ContentItem[]> {
    const qs = params ? "?" + new URLSearchParams(params).toString() : "";
    const baseUrl =
        typeof window === "undefined"
            ? process.env.NEXT_PUBLIC_BASE_URL ?? "http://localhost:3000"
            : "";
    const res = await fetch(`${baseUrl}/api/content${qs}`, {
        next: { revalidate: 10 }, // ISR: re-fetch every 10s on server
    });
    if (!res.ok) return [];
    const json = await res.json();
    return (json.data as ContentRecord[]).map(toContentItem);
}
