"use client";

import { useState, useEffect, useCallback } from "react";
import { useWallet } from "@solana/wallet-adapter-react";
import { useConnection } from "@solana/wallet-adapter-react";
import { PublicKey, Transaction, SystemProgram } from "@solana/web3.js";
import { checkAccess } from "@/lib/solana";
import { ContentItem } from "@/lib/content";

// ── LocalStorage helpers (POC fallback until Anchor program is deployed) ──────
// Key: "solstream_access_<walletAddress>_<contentId>"
function localAccessKey(wallet: PublicKey, contentId: bigint) {
    return `solstream_access_${wallet.toBase58()}_${contentId.toString()}`;
}

function hasLocalAccess(wallet: PublicKey, contentId: bigint): boolean {
    try {
        return localStorage.getItem(localAccessKey(wallet, contentId)) === "1";
    } catch {
        return false;
    }
}

function grantLocalAccess(wallet: PublicKey, contentId: bigint) {
    try {
        localStorage.setItem(localAccessKey(wallet, contentId), "1");
    } catch {
        // ignore
    }
}

// ── useHasAccess ──────────────────────────────────────────────────────────────

export function useHasAccess(content: ContentItem | null) {
    const { publicKey } = useWallet();
    const [hasAccess, setHasAccess] = useState(false);
    const [loading, setLoading] = useState(false);

    const refresh = useCallback(async () => {
        if (!publicKey || !content) {
            setHasAccess(false);
            return;
        }
        setLoading(true);
        try {
            // 1. Check on-chain PDA first (works once the Anchor program is deployed).
            const onChain = await checkAccess(publicKey, content.id);
            if (onChain) {
                setHasAccess(true);
                return;
            }
            // 2. Fallback: check localStorage for purchases made in this POC demo.
            setHasAccess(hasLocalAccess(publicKey, content.id));
        } finally {
            setLoading(false);
        }
    }, [publicKey, content]);

    useEffect(() => {
        refresh();
    }, [refresh]);

    return { hasAccess, loading, refresh };
}

// ── usePurchase ───────────────────────────────────────────────────────────────

export function usePurchase(content: ContentItem | null) {
    const { publicKey, sendTransaction } = useWallet();
    const { connection } = useConnection();
    const [purchasing, setPurchasing] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [txSig, setTxSig] = useState<string | null>(null);

    const purchase = useCallback(async (): Promise<boolean> => {
        if (!publicKey || !content) {
            setError("Wallet not connected.");
            return false;
        }

        setPurchasing(true);
        setError(null);
        setTxSig(null);

        try {
            const streamerPubkey = new PublicKey(content.streamer);

            // POC: simple SOL transfer to the streamer.
            // Full version: CPI into the Anchor program's purchase_content instruction.
            const tx = new Transaction().add(
                SystemProgram.transfer({
                    fromPubkey: publicKey,
                    toPubkey: streamerPubkey,
                    lamports: Number(content.priceLamports),
                })
            );

            const { blockhash, lastValidBlockHeight } =
                await connection.getLatestBlockhash();
            tx.recentBlockhash = blockhash;
            tx.feePayer = publicKey;

            const sig = await sendTransaction(tx, connection);

            // Wait for confirmation with the proper strategy
            await connection.confirmTransaction(
                { signature: sig, blockhash, lastValidBlockHeight },
                "confirmed"
            );

            // ✅ TX confirmed — record access in both localStorage and the API.
            grantLocalAccess(publicKey, content.id);

            // Fire-and-forget: record the purchase in the API so the
            // /api/content/:id/access/:wallet endpoint returns true,
            // and so creators can see their sales via GET /api/content/:id/purchase.
            fetch(`/api/content/${content.id.toString()}/purchase`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    buyer_wallet: publicKey.toBase58(),
                    tx_signature: sig,
                }),
            }).catch(() => {/* non-critical — localStorage is the primary fallback */ });

            setTxSig(sig);
            return true;
        } catch (e: unknown) {
            const msg = e instanceof Error ? e.message : "Transaction failed.";
            setError(msg);
            return false;
        } finally {
            setPurchasing(false);
        }
    }, [publicKey, content, connection, sendTransaction]);

    return { purchase, purchasing, error, txSig };
}
